import React, { useState } from 'react';
import { Code, Cpu, Zap} from 'lucide-react';
import './WorkshopsPage.css';

export default function WorkshopsPage() {
  const [selectedCategory, setSelectedCategory] = useState('All');

  const workshops = [
    {
      id: 1,
      title: 'Drone',
      category: 'Semester 1',
      description: 'Learn the basics of Arduino programming and build your first embedded system project.',
      instructor: 'Dr. James Lee',
      startDate: 'Mar 15, 2025',
      icon: Cpu,
    },
    {
      id: 2,
      title: 'Drone',
      category: 'Semester 2',
      description: 'Master Python programming with focus on robotics control, automation, and AI applications.',
      instructor: 'Engineer Mike',
      startDate: 'Mar 20, 2025',
      icon: Code,
    },
    {
      id: 3,
      title: 'Microcontroller Agroteknologi',
      category: 'Semester 3',
      description: 'Design and build functional circuits using breadboards, resistors, capacitors, and more.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
      icon: Zap,
    },
    {
      id: 4,
      title: 'Microcontroller Kesehatan',
      category: 'Semester 3',
      description: 'Design and build functional circuits using breadboards, resistors, capacitors, and more.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
      icon: Zap,
    },
    {
      id: 5,
      title: 'Raspberry Pi - Dasar',
      category: 'Semester 4',
      description: 'Design and build functional circuits using breadboards, resistors, capacitors, and more.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
      icon: Zap,
    },
    {
      id: 6,
      title: 'Raspberry Pi - Robot',
      category: 'Semester 5',
      description: 'Design and build functional circuits using breadboards, resistors, capacitors, and more.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
      icon: Zap,
    },
    {
      id: 7,
      title: 'Raspberry Pi - Face Recognition',
      category: 'Semester 6',
      description: 'Design and build functional circuits using breadboards, resistors, capacitors, and more.',
      instructor: 'Prof. Emma',
      startDate: 'Mar 10, 2025',
      icon: Zap,
    },
  ];

  const categories = ['All', 'Semester 1', 'Semester 2', 'Semester 3', 'Semester 4', 'Semester 5', 'Semester 6'];
  const filteredWorkshops = selectedCategory === 'All' ? workshops : workshops.filter(w => w.category === selectedCategory);

  return (
    <>
      <section className="page-header">
        <div className="container">
          <h1>Workshops MURO</h1>
          <p>Level up your skills with our hands-on learning programs</p>
        </div>
      </section>

      <section className="workshops-section">
        <div className="container">
          {/* Category Filter */}
          <div className="category-filter">
            {categories.map(category => (
              <button
                key={category}
                className={`category-btn ${selectedCategory === category ? 'active' : ''}`}
                onClick={() => setSelectedCategory(category)}
              >
                {category}
              </button>
            ))}
          </div>

          {/* Workshops Grid */}
          <div className="workshops-grid">
            {filteredWorkshops.map(workshop => {
              const Icon = workshop.icon;
              return (
                <div key={workshop.id} className="workshop-card">
                  <div className="workshop-header">
                    <div className="workshop-icon">
                      <Icon size={32} />
                    </div>
                  </div>

                  <h3 className="workshop-title">{workshop.title}</h3>
                  <p className="workshop-description">{workshop.description}</p>
                  <p className="workshop-instructor"><strong>Instructor:</strong> {workshop.instructor}</p>
                  <p className="workshop-date"><strong>Starts:</strong> {workshop.startDate}</p>

                  <button className="btn-enroll">Pengajuan Blanko</button>
                  <button className="btn-enroll">Konfirmasi Pembayaran</button>
                </div>
              );
            })}
          </div>
        </div>
      </section>
    </>
  );
}
